INSERT INTO public.exercise_details (id, name, primary_muscle, steps, form_cues)
VALUES
  ('ex-push-ups', 'Push-ups', 'Full Body', '{"Start in a high plank position with your hands slightly wider than shoulder-width apart.","Keep your core engaged, back flat, and neck neutral.","Lower your body until your chest nearly touches the floor.","Push back up to the starting position."}', '{"Keep elbows tucked at a 45-degree angle.","Squeeze your glutes and brace your core."}'),
  ('ex-db-bench-press', 'Dumbbell Bench Press', 'Chest', '{"Lie back on the bench holding dumbbells directly above your chest","Lower the dumbbells slowly until they are in line with your chest","Press the dumbbells back up to the starting position"}', '{"Keep your feet flat on the ground","Squeeze shoulders down and back"}'),
  ('ex-bb-bench-press', 'Barbell Bench Press', 'Full Body', '{"Lie on the bench with your eyes under the bar.","Grip the bar slightly wider than shoulder-width.","Unrack the bar and lower it to your mid-chest.","Press the bar back up in a slight arc toward your shoulders."}', '{"Drive through your heels.","Pull the bar apart to engage your lats."}'),
  ('ex-inc-db-press', 'Incline Dumbbell Press', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-mach-chest-press', 'Machine Chest Press', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-db-flyes', 'Dumbbell Flyes', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-cable-cross', 'Cable Crossovers', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-band-chest-press', 'Resistance Band Chest Press', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-arm-circles', 'Arm Circles', 'Chest', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-pull-ups', 'Pull-ups', 'Full Body', '{"Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width.","Hang with your arms fully extended and core engaged.","Pull yourself up until your chin clears the bar.","Lower yourself slowly back to the starting position."}', '{"Drive your elbows down to the floor.","Keep your chest up."}'),
  ('ex-lat-pulldown', 'Lat Pulldown', 'Full Body', '{"Sit at the pulldown machine and adjust the knee pad.","Grip the bar wider than shoulder-width.","Pull the bar down toward your upper chest.","Slowly return the bar to the starting position."}', '{"Lean back slightly (about 10-15 degrees).","Squeeze your shoulder blades together at the bottom."}'),
  ('ex-bb-row', 'Barbell Row', 'Full Body', '{"Stand with feet shoulder-width apart, holding a barbell with an overhand grip.","Hinge at the hips, keeping your back straight and nearly parallel to the floor.","Row the barbell toward your lower chest/upper stomach.","Lower the bar under control."}', '{"Pull your elbows straight back.","Keep your chest up and lower back neutral."}'),
  ('ex-db-row', 'Dumbbell Row', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-seated-cable-row', 'Seated Cable Row', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-straight-arm-pulldown', 'Straight Arm Pulldown', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-superman-hold', 'Superman Hold', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-inverted-rows', 'Inverted Rows (Table)', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-cat-cow', 'Cat-Cow Stretch', 'Back', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-overhead-press', 'Overhead Press', 'Shoulders', '{"Stand with feet shoulder-width apart, holding dumbbells at shoulder height","Press the weights straight up overhead until arms are extended","Lower under control back to shoulders"}', '{"Brace your core","Do not arch your lower back aggressively"}'),
  ('ex-pike-pushups', 'Pike Push-ups', 'Shoulders', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-lateral-raise', 'Lateral Raise', 'Shoulders', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-front-raise', 'Front Raise', 'Shoulders', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-face-pulls', 'Face Pulls', 'Full Body', '{"Attach a rope to a cable pulley set at upper-chest height.","Grip the rope from underneath and step back.","Pull the rope toward your face, letting your elbows flare high and wide.","Squeeze your upper back, then slowly return."}', '{"Imagine hitting a back double bicep pose.","Pull the center of the rope to your nose."}'),
  ('ex-mach-shoulder-press', 'Machine Shoulder Press', 'Shoulders', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-shoulder-dislocations', 'Shoulder Dislocations (Broomstick)', 'Shoulders', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-bb-squat', 'Barbell Squat', 'Quads / Glutes', '{"Unrack the barbell across your upper back, stepping back","Squat down by pushing hips back and bending knees","Drive through your heels to return to standing"}', '{"Chest up","Knees track over toes","Brace core"}'),
  ('ex-goblet-squat', 'Goblet Squat', 'Full Body', '{"Hold a dumbbell or kettlebell vertically against your chest.","Stand with feet slightly wider than shoulder-width.","Lower your hips down and back until your thighs are parallel to the floor.","Drive back to the starting position."}', '{"Keep your elbows tucked inside your knees at the bottom.","Keep the weight close to your body."}'),
  ('ex-bodyweight-squat', 'Bodyweight Squats', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-leg-press', 'Leg Press', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-rdl', 'Romanian Deadlift', 'Full Body', '{"Hold a barbell or dumbbells in front of your thighs.","Hinge at your hips, pushing them back while keeping your legs mostly straight (slight bend in the knee).","Lower the weight until you feel a deep stretch in your hamstrings.","Squeeze your glutes to return to a standing position."}', '{"Keep the bar/dumbbells dragging closely along your legs.","Maintain a flat, neutral back."}'),
  ('ex-lunges', 'Lunges', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-leg-extensions', 'Leg Extensions', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-leg-curls', 'Leg Curls', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-calf-raises', 'Calf Raises', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-leg-swings', 'Leg Swings', 'Legs', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-bicep-curls', 'Bicep Curls', 'Full Body', '{"Stand holding dumbbells with your palms facing forward.","Keep your upper arms stationary against your sides.","Curl the weights up toward your shoulders by flexing your elbows.","Lower the weights slowly."}', '{"Squeeze your biceps at the top.","Control the eccentric (lowering) phase."}'),
  ('ex-hammer-curls', 'Hammer Curls', 'Arms', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-tricep-pushdown', 'Tricep Pushdown', 'Full Body', '{"Attach a rope or straight bar to a high cable pulley.","Grip the attachment and tuck your elbows to your sides.","Push the attachment down until your arms are fully extended.","Return slowly to the starting position."}', '{"Keep your elbows pinned to your ribs.","Spread the rope apart at the bottom for an extra squeeze."}'),
  ('ex-overhead-tricep-ext', 'Overhead Tricep Extension', 'Arms', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-tricep-dips', 'Tricep Dips', 'Arms', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
  ('ex-plank', 'Plank', 'Full Body', '{"Start on your forearms and toes, with your elbows directly under your shoulders.","Keep your body in a straight line from your head to your heels.","Engage your core, glutes, and quads.","Hold the position for the specified duration."}', '{"Pull your belly button toward your spine.","Push the floor away with your forearms."}'),
  ('ex-bicycle-crunches', 'Bicycle Crunches', 'Core', '{"Consult your coach for proper form.","Maintain steady breathing.","Control the movement."}', '{"Focus on the target muscle.","Keep your core engaged."}'),
